+    fn span(sl: usize, sc: usize, el: usize, ec: usize) -> Span {
+        Span { start: pos(sl, sc), end: pos(el, ec) }
+    }
+
+    const MAIN_DOC: &str = "---\nmodule: auth/session\ndeps: [auth/tokens, auth/users]\ntargets: [typescript]\n---\n# Session\n\nManage sessions. See @auth/tokens and @auth/users for details.\nRefreshes via @auth/session.\n";
+
+    #[test]
+    fn main_doc_module_value() {
+        let result = scan(MAIN_DOC);
+        let mv = result.module_value.expect("module value present");
+        assert_eq!(mv.value, "auth/session");
+        assert_eq!(mv.span, span(1, 8, 1, 20));
+    }
+
+    #[test]
+    fn main_doc_deps() {
+        let result = scan(MAIN_DOC);
+        assert_eq!(result.deps.len(), 2);
+        assert_eq!(result.deps[0].value, "auth/tokens");
+        assert_eq!(result.deps[0].source, DepSource::Deps);
+        assert_eq!(result.deps[0].span, span(2, 7, 2, 18));
+        assert_eq!(result.deps[1].value, "auth/users");
+        assert_eq!(result.deps[1].span.start, pos(2, 20));
+        assert_eq!(result.deps[1].span.end, pos(2, 30));
+    }
+
+    #[test]
+    fn main_doc_refs() {
+        let result = scan(MAIN_DOC);
+        let names: Vec<&str> = result.refs.iter().map(|r| r.module.as_str()).collect();
+        assert_eq!(names, vec!["auth/tokens", "auth/users", "auth/session"]);
+        assert_eq!(result.refs[0].span, span(7, 21, 7, 33));
+    }
+
+    #[test]
+    fn main_doc_regions() {
+        let result = scan(MAIN_DOC);
+        assert!(result.frontmatter.present);
+        assert_eq!(result.frontmatter.span.unwrap().start, pos(1, 0));
+        assert_eq!(result.frontmatter.span.unwrap().end.line, 3);
+        assert!(result.body.present);
+        assert_eq!(result.body.span.unwrap().start.line, 5);
+    }
+
+    #[test]
+    fn main_doc_find_target() {
+        let result = scan(MAIN_DOC);
+        match find_target_at_position(&result, pos(1, 10)) {
+            Some(Target::ModuleValue { module, .. }) => assert_eq!(module, "auth/session"),
+            other => panic!("unexpected: {:?}", other),
+        }
+        match find_target_at_position(&result, pos(2, 10)) {
+            Some(Target::Dep { module, source, .. }) => {
+                assert_eq!(module, "auth/tokens");
+                assert_eq!(source, DepSource::Deps);
+            }
+            other => panic!("unexpected: {:?}", other),
+        }
+        match find_target_at_position(&result, pos(7, 25)) {
+            Some(Target::Ref { module, .. }) => assert_eq!(module, "auth/tokens"),
+            other => panic!("unexpected: {:?}", other),
+        }
+        assert!(find_target_at_position(&result, pos(5, 0)).is_none());
+    }
+
+    #[test]
+    fn block_list_deps() {
+        let doc = "---\nmodule: a\ndeps:\n  - one\n  - \"two/x\"\nextends: base\n---\nbody\n";
+        let result = scan(doc);
+        assert_eq!(result.deps.len(), 3);
+
+        assert_eq!(result.deps[0].source, DepSource::Deps);
+        assert_eq!(result.deps[0].value, "one");
+        assert_eq!(result.deps[0].span, span(3, 4, 3, 7));
+
+        assert_eq!(result.deps[1].source, DepSource::Deps);
+        assert_eq!(result.deps[1].value, "two/x");
+        assert_eq!(result.deps[1].span.start, pos(4, 5));
+
+        assert_eq!(result.deps[2].source, DepSource::Extends);
+        assert_eq!(result.deps[2].value, "base");
+        assert_eq!(result.deps[2].span.start, pos(5, 9));
+    }
+
+    #[test]
+    fn empty_inline_list() {
+        let doc = "---\nmodule: greeting\ndeps: []\n---\nbody\n";
+        let result = scan(doc);
+        assert!(result.deps.is_empty());
+        assert_eq!(result.module_value.unwrap().value, "greeting");
+    }
+
+    #[test]
+    fn astral_emoji_ref_offset() {
+        let doc = "---\nmodule: m\n---\n\u{1F600}\u{1F600}@auth/x\n";
+        let result = scan(doc);
+        assert_eq!(result.refs.len(), 1);
+        assert_eq!(result.refs[0].module, "auth/x");
+        assert_eq!(result.refs[0].span, span(3, 4, 3, 11));
+    }
+
+    #[test]
+    fn bmp_char_ref_offset() {
+        let doc = "---\nmodule: m\n---\n\u{00E9}@x/y\n";
+        let result = scan(doc);
+        assert_eq!(result.refs.len(), 1);
+        assert_eq!(result.refs[0].span.start, pos(3, 1));
+    }
+
+    #[test]
+    fn no_frontmatter_body_present() {
+        let doc = "# just a heading\nwith @a/b ref\n";
+        let result = scan(doc);
+        assert!(!result.frontmatter.present);
+        assert!(result.body.present);
+        assert_eq!(result.body.span.unwrap().start, pos(0, 0));
+        assert_eq!(result.refs.len(), 1);
+        assert_eq!(result.refs[0].module, "a/b");
+    }
+
+    #[test]
+    fn frontmatter_with_no_body_after() {
+        // trailing "\n" still yields one empty body line, so body is present but empty
+        let doc = "---\nmodule: a\n---\n";
+        let result = scan(doc);
+        assert!(result.frontmatter.present);
+        assert!(result.body.present);
+        assert_eq!(result.body.span.unwrap(), span(3, 0, 3, 0));
+    }
+
+    #[test]
+    fn frontmatter_with_truly_nothing_after() {
+        let doc = "---\nmodule: a\n---";
+        let result = scan(doc);
+        assert!(result.frontmatter.present);
+        assert!(!result.body.present);
+    }
+
+    #[test]
+    fn bare_at_is_not_a_ref() {
+        let doc = "hello @ world\n";
+        let result = scan(doc);
+        assert!(result.refs.is_empty());
+    }
+
+    #[test]
+    fn dash_without_space_is_not_block_item() {
+        let doc = "---\nmodule: a\ndeps:\n  -nospace\n---\nbody\n";
+        let result = scan(doc);
+        assert!(result.deps.is_empty());
+    }
+
+    #[test]
+    fn crlf_lines_behave_like_lf() {
+        let doc = "---\r\nmodule: a\r\n---\r\nbody\r\n";
+        let result = scan(doc);
+        assert!(result.frontmatter.present);
+        assert_eq!(result.module_value.unwrap().value, "a");
